1	import "server-only";
2	import fs from "node:fs";
3	import path from "node:path";
4	import winston from "winston";
5	import { env } from "@/lib/env";
6	
7	const IS_PROD = env.NODE_ENV === "production";
8	const IS_TEST = env.NODE_ENV === "test";
9	
10	const LOG_LEVEL = env.LOG_LEVEL ?? (IS_PROD ? "info" : "debug");
11	const LOG_DIR = env.LOG_DIR ?? path.join(process.cwd(), "logs");
12	
13	// ─── Levels ──────────────────────────────────────────────────────────────────
14	
15	const levels = {
16	  error: 0,
17	  warn: 1,
18	  info: 2,
19	  http: 3,
20	  debug: 4,
21	};
22	
23	winston.addColors({
24	  error: "red",
25	  warn: "yellow",
26	  info: "green",
27	  http: "magenta",
28	  debug: "blue",
29	});
30	
31	// ─── Formats ─────────────────────────────────────────────────────────────────
32	
33	const SENSITIVE_KEYS = new Set(["password", "token", "authorization", "secret", "apikey"]);
34	
35	// Mutates in-place to preserve Winston's internal Symbol properties (e.g. Symbol(level)).
36	// Handles nested objects and arrays of objects.
37	const redactInPlace = (obj: Record<string, unknown>): void => {
38	  for (const key of Object.keys(obj)) {
39	    if (SENSITIVE_KEYS.has(key.toLowerCase())) {
40	      obj[key] = "[REDACTED]";
41	    } else if (Array.isArray(obj[key])) {
42	      for (const item of obj[key] as unknown[]) {
43	        if (item && typeof item === "object") {
44	          redactInPlace(item as Record<string, unknown>);
45	        }
46	      }
47	    } else if (obj[key] && typeof obj[key] === "object") {
48	      redactInPlace(obj[key] as Record<string, unknown>);
49	    }
50	  }
51	};
52	
53	const redact = winston.format((info) => {
54	  redactInPlace(info as unknown as Record<string, unknown>);
55	  return info;
56	});
57	
58	const consoleFormat = winston.format.combine(
59	  winston.format.timestamp({ format: "YYYY-MM-DD HH:mm:ss" }),
60	  winston.format.colorize({ all: true }),
61	  winston.format.printf(({ timestamp, level, message, stack, ...meta }) => {
62	    const hasMeta = Object.keys(meta).length > 0;
63	    const metaStr = hasMeta ? `\n${JSON.stringify(meta, null, 2)}` : "";
64	    return `${timestamp} [${level}]: ${message}${stack ? `\n${stack}` : ""}${metaStr}`;
65	  })
66	);
67	
68	const fileFormat = winston.format.combine(winston.format.timestamp(), winston.format.json());
69	
70	// ─── Transports ──────────────────────────────────────────────────────────────
71	
72	let logsDirCreated = false;
73	
74	const ensureLogsDir = () => {
75	  if (logsDirCreated) return;
76	  if (!fs.existsSync(LOG_DIR)) fs.mkdirSync(LOG_DIR, { recursive: true });
77	  logsDirCreated = true;
78	};
79	
80	// Builds transport list at runtime based on NODE_ENV.
81	// Development: console only. Production: console + rotating files.
82	// This keeps dev logs readable in terminal while persisting logs in prod.
83	const buildTransports = (): winston.transport[] => {
84	  const transports: winston.transport[] = [
85	    new winston.transports.Console({ format: consoleFormat }),
86	  ];
87	
88	  if (IS_PROD) {
89	    ensureLogsDir();
90	
91	    transports.push(
92	      // Errors only — small, fast to scan
93	      new winston.transports.File({
94	        filename: path.join(LOG_DIR, "error.log"),
95	        level: "error",
96	        format: fileFormat,
97	        maxsize: 10 * 1024 * 1024, // 10 MB
98	        maxFiles: 5,
99	      }),
100	      // Everything
101	      new winston.transports.File({
102	        filename: path.join(LOG_DIR, "combined.log"),
103	        format: fileFormat,
104	        maxsize: 20 * 1024 * 1024, // 20 MB
105	        maxFiles: 10,
106	      })
107	    );
108	  }
109	
110	  return transports;
111	};
112	
113	const buildExceptionHandlers = (): winston.transport[] => {
114	  if (!IS_PROD) return [];
115	  ensureLogsDir();
116	  return [
117	    new winston.transports.File({
118	      filename: path.join(LOG_DIR, "exceptions.log"),
119	      format: fileFormat,
120	    }),
121	  ];
122	};
123	
124	const buildRejectionHandlers = (): winston.transport[] => {
125	  if (!IS_PROD) return [];
126	  ensureLogsDir();
127	  return [
128	    new winston.transports.File({
129	      filename: path.join(LOG_DIR, "rejections.log"),
130	      format: fileFormat,
131	    }),
132	  ];
133	};
134	
135	// ─── Logger ──────────────────────────────────────────────────────────────────
136	
137	const logger = winston.createLogger({
138	  level: LOG_LEVEL,
139	  levels,
140	  silent: IS_TEST,
141	  // redact() runs before any transport so sensitive keys are scrubbed from
142	  // both console and file output, including stdout captured in production.
143	  format: winston.format.combine(redact(), winston.format.errors({ stack: true })),
144	  transports: buildTransports(),
145	  exceptionHandlers: buildExceptionHandlers(),
146	  rejectionHandlers: buildRejectionHandlers(),
147	});
148	
149	// ─── Child logger factory ─────────────────────────────────────────────────────
150	// Usage: const log = childLogger("auth"); log.info("user signed in");
151	
152	export const childLogger = (service: string) => logger.child({ service });
153	
154	// ─── Helpers ──────────────────────────────────────────────────────────────────
155	
156	export const logError = (message: string, error?: unknown, meta?: Record<string, unknown>) => {
157	  const err = error instanceof Error ? error : new Error(String(error));
158	  // Pass stack as a top-level key so printf renders it and JSON transport includes it.
159	  // JSON.stringify(Error) returns "{}" — never pass Error objects directly in meta.
160	  logger.error(message, { stack: err.stack, ...meta });
161	};
162	
163	export const logHttp = (method: string, url: string, status?: number, duration?: number) => {
164	  logger.http(`${method} ${url}`, { status, duration });
165	};
166	
167	export default logger;
168

