3	import { useRouter } from "next/navigation";
4	import { useEffect, useMemo, useState } from "react";
5	import { CareerPreferencesSection } from "@/components/profile/career-preferences-section";
6	import { EducationSection } from "@/components/profile/education-section";
7	import { ExperienceSection } from "@/components/profile/experience-section";
8	import { IdentitySection } from "@/components/profile/identity-section";
9	import { SkillsSection } from "@/components/profile/skills-section";
10	import { SummarySection } from "@/components/profile/summary-section";
11	import { CompletionIndicator } from "@/components/ui/completion-indicator";
12	import { ProfileSkeleton } from "@/components/ui/skeletons/profile-skeleton";
13	import { showToast } from "@/components/ui/toast";
14	import type { CompletionField, ProfileData } from "@/types/profile";
15	
16	const EMPTY_PROFILE: ProfileData = {
17	  targetRoles: [],
18	  targetLocations: [],
19	  experiences: [],
20	  educations: [],
21	  skills: [],
22	};
23	
24	function getCompletionFields(profile: ProfileData): CompletionField[] {
25	  return [
26	    { label: "First name", complete: !!profile.firstName },
27	    { label: "Last name", complete: !!profile.lastName },
28	    { label: "Email", complete: !!profile.email },
29	    { label: "Phone", complete: !!profile.phone },
30	    { label: "Location", complete: !!profile.location },
31	    { label: "Headline", complete: !!profile.headline },
32	    { label: "Summary", complete: !!profile.summary },
33	    { label: "Experience", complete: profile.experiences.length > 0 },
34	    { label: "Education", complete: profile.educations.length > 0 },
35	    { label: "Skills", complete: profile.skills.length > 0 },
36	    { label: "Target roles", complete: profile.targetRoles.length > 0 },
37	    { label: "Work mode", complete: !!profile.workModePreference },
38	  ];
39	}
40	
41	export default function ProfilePage() {
42	  const router = useRouter();
43	  const [profile, setProfile] = useState<ProfileData>(EMPTY_PROFILE);
44	  const [loading, setLoading] = useState(true);
45	
46	  useEffect(() => {
47	    fetch("/api/profile")
48	      .then((res) => {
49	        if (res.status === 401) {
50	          router.push("/login");
51	          return null;
52	        }
53	        return res.json();
54	      })
55	      .then((data) => {
56	        if (data && typeof data === "object") {
57	          setProfile((prev) => ({ ...EMPTY_PROFILE, ...prev, ...data }));
58	        }
59	      })
60	      .finally(() => setLoading(false));
61	  }, [router]);
62	
63	  async function handleUpdate(fields: Partial<ProfileData>, message?: string) {
64	    const merged = { ...profile, ...fields };
65	    setProfile(merged);
66	
67	    const payload = Object.fromEntries(
68	      Object.entries(fields).map(([k, v]) => [k, v === undefined ? null : v])
69	    );
70	    const res = await fetch("/api/profile", {
71	      method: "PUT",
72	      headers: { "Content-Type": "application/json" },
73	      body: JSON.stringify(payload),
74	    });
75	
76	    if (res.status === 401) {
77	      router.push("/login");
78	      return;
79	    }
80	
81	    if (res.ok) {
82	      const saved: ProfileData = await res.json();
83	      setProfile(saved);
84	      showToast(message ?? "Profile updated");
85	      router.refresh();
86	    } else {
87	      setProfile(profile);
88	      showToast("Failed to update profile", "error");
89	    }
90	  }
91	
92	  const completionFields = useMemo(() => getCompletionFields(profile), [profile]);
93	
94	  if (loading) {
95	    return <ProfileSkeleton />;
96	  }
97	
98	  return (
99	    <>
100	      <div className="mb-8">
101	        <h1 className="text-2xl font-semibold text-zinc-50">Profile</h1>
102	        <p className="mt-1 text-sm text-zinc-400">
103	          Build your profile to tailor resumes and cover letters.
104	        </p>
105	      </div>
106	
107	      <div className="space-y-8">
108	        <CompletionIndicator
109	          items={completionFields}
110	          totalLabel={`${completionFields.filter((f) => f.complete).length} of ${completionFields.length} complete`}
111	        />
112	        <IdentitySection
113	          profile={profile}
114	          onUpdate={(f) => handleUpdate(f, "Contact info updated")}
115	        />
116	        <SummarySection profile={profile} onUpdate={(f) => handleUpdate(f, "Summary updated")} />
117	        <ExperienceSection
118	          experiences={profile.experiences}
119	          onUpdate={(experiences, msg) => handleUpdate({ experiences }, msg)}
120	        />
121	        <EducationSection
122	          educations={profile.educations}
123	          onUpdate={(educations, msg) => handleUpdate({ educations }, msg)}
124	        />
125	        <SkillsSection
126	          skills={profile.skills}
127	          onUpdate={(skills, msg) => handleUpdate({ skills }, msg)}
128	        />
129	        <CareerPreferencesSection
130	          profile={profile}
131	          onUpdate={(f) => handleUpdate(f, "Career preferences updated")}
132	        />
133	      </div>
134	    </>
135	  );
136	}
