"use client";

import { useState } from "react";
import { DatePicker } from "@/components/ui/date-picker";
import { Select } from "@/components/ui/select";
import type { Job, JobStage } from "@/types/job";

type JobFormProps = {
  initialValues?: Job | null;
  onSubmit: (job: Job) => void;
  onCancel: () => void;
};

const STAGES: JobStage[] = ["Interested", "Applied", "Interview", "Offer", "Rejected", "Archived"];

const inputStyles =
  "w-full bg-zinc-800 border border-zinc-700 rounded-md px-3 py-2 text-sm text-zinc-50 placeholder:text-zinc-500 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent";

const labelStyles = "mb-1 block text-sm font-medium text-zinc-300";

export default function JobForm({ initialValues, onSubmit, onCancel }: JobFormProps) {
  const [title, setTitle] = useState(initialValues?.title ?? "");
  const [company, setCompany] = useState(initialValues?.company ?? "");
  const [location, setLocation] = useState(initialValues?.location ?? "");
  const [stage, setStage] = useState<JobStage>(initialValues?.stage ?? "Interested");
  const [lastActivityDate, setLastActivityDate] = useState(
    initialValues?.lastActivityDate ?? new Date().toISOString().slice(0, 10)
  );
  const [priority, setPriority] = useState(initialValues?.priority ?? false);

  function handleSubmit(event: React.FormEvent<HTMLFormElement>) {
    event.preventDefault();

    if (!title.trim() || !company.trim()) {
      return;
    }

    onSubmit({
      id: initialValues?.id ?? crypto.randomUUID(),
      title: title.trim(),
      company: company.trim(),
      location: location.trim(),
      stage,
      lastActivityDate,
      priority,
    });
  }

  return (
    <form className="space-y-4" onSubmit={handleSubmit}>
      <div>
        <label className={labelStyles} htmlFor="title">
          Job Title
        </label>
        <input
          id="title"
          type="text"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          className={inputStyles}
          placeholder="Software Engineer Intern"
          required
        />
      </div>

      <div>
        <label className={labelStyles} htmlFor="company">
          Company
        </label>
        <input
          id="company"
          type="text"
          value={company}
          onChange={(e) => setCompany(e.target.value)}
          className={inputStyles}
          placeholder="Google"
          required
        />
      </div>

      <div>
        <label className={labelStyles} htmlFor="location">
          Location
        </label>
        <input
          id="location"
          type="text"
          value={location}
          onChange={(e) => setLocation(e.target.value)}
          className={inputStyles}
          placeholder="Mountain View, CA"
        />
      </div>

      <div>
        <label className={labelStyles} htmlFor="stage">
          Stage
        </label>
        <Select
          id="stage"
          value={stage}
          onChange={(val) => setStage(val as JobStage)}
          options={STAGES.map((s) => ({ value: s, label: s }))}
        />
      </div>

      <DatePicker
        id="lastActivityDate"
        label="Last Activity Date"
        value={lastActivityDate}
        onChange={setLastActivityDate}
        placeholder="Select date"
        required
      />

      <label className="flex items-center gap-2 text-sm text-zinc-300">
        <input
          type="checkbox"
          checked={priority}
          onChange={(e) => setPriority(e.target.checked)}
          className="accent-indigo-500"
        />
        Mark as priority
      </label>

      <div className="flex justify-end gap-3 pt-2">
        <button
          type="button"
          onClick={onCancel}
          className="bg-zinc-800 border border-zinc-700 hover:bg-zinc-700 text-zinc-50 px-4 py-2 rounded-md text-sm font-medium"
        >
          Cancel
        </button>
        <button
          type="submit"
          className="bg-indigo-500 hover:bg-indigo-600 text-zinc-50 px-4 py-2 rounded-md text-sm font-medium"
        >
          {initialValues ? "Update Job" : "Add Job"}
        </button>
      </div>
    </form>
  );
}

// This is the sidebar component used in layout.tsx.
// It renders the Dartly logo + the four main nav links.
// "use client" is required here because we use usePathname()
// to detect which page is active and style it differently.

"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
// cn() is a utility already in the project (src/utils/cn.ts).
// It merges Tailwind classes cleanly so we can write conditional styles.
import { cn } from "@/utils/cn";

// ---------------------------------------------------------------------------
// Nav link definitions
// Each item has: the display label, the URL it goes to, and a simple SVG icon.
// To add a new nav item in the future, just add an entry here.
// ---------------------------------------------------------------------------
const NAV_ITEMS = [
  {
    label: "Dashboard",
    href: "/dashboard",
    icon: (
      <svg
        width="18"
        height="18"
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth="1.75"
        strokeLinecap="round"
        strokeLinejoin="round"
        aria-hidden="true"
      >
        <rect x="3" y="3" width="7" height="7" rx="1" />
        <rect x="14" y="3" width="7" height="7" rx="1" />
        <rect x="3" y="14" width="7" height="7" rx="1" />
        <rect x="14" y="14" width="7" height="7" rx="1" />
      </svg>
    ),
  },
  {
    label: "Documents",
    href: "/documents",
    icon: (
      <svg
        width="18"
        height="18"
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth="1.75"
        strokeLinecap="round"
        strokeLinejoin="round"
        aria-hidden="true"
      >
        <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z" />
        <polyline points="14 2 14 8 20 8" />
        <line x1="8" y1="13" x2="16" y2="13" />
        <line x1="8" y1="17" x2="16" y2="17" />
      </svg>
    ),
  },
  {
    label: "Profile",
    href: "/profile",
    icon: (
      <svg
        width="18"
        height="18"
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth="1.75"
        strokeLinecap="round"
        strokeLinejoin="round"
        aria-hidden="true"
      >
        <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2" />
        <circle cx="12" cy="7" r="4" />
      </svg>
    ),
  },
  {
    label: "Settings",
    href: "/settings",
    icon: (
      <svg
        width="18"
        height="18"
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth="1.75"
        strokeLinecap="round"
        strokeLinejoin="round"
        aria-hidden="true"
      >
        <circle cx="12" cy="12" r="3" />
        <path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1-2.83 2.83l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-4 0v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83-2.83l.06-.06A1.65 1.65 0 0 0 4.68 15a1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1 0-4h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 2.83-2.83l.06.06A1.65 1.65 0 0 0 9 4.68a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 4 0v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 2.83l-.06.06A1.65 1.65 0 0 0 19.4 9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 0 4h-.09a1.65 1.65 0 0 0-1.51 1z" />
      </svg>
    ),
  },
] as const;

// ---------------------------------------------------------------------------
// Sidebar component
// ---------------------------------------------------------------------------
type SidebarProps = {
  firstName?: string;
  lastName?: string;
};

export function Sidebar({ firstName, lastName }: SidebarProps) {
  const pathname = usePathname();

  const initials =
    firstName || lastName
      ? `${(firstName ?? "")[0] ?? ""}${(lastName ?? "")[0] ?? ""}`.toUpperCase()
      : "?";
  const fullName =
    firstName || lastName ? `${firstName ?? ""} ${lastName ?? ""}`.trim() : "Profile";

  return (
    <aside
      className="w-56 shrink-0 flex flex-col border-r border-zinc-800 bg-zinc-950 sticky top-0 h-screen"
      aria-label="Main navigation"
    >
      {/* ----------------------------------------------------------------
          Logo / Wordmark
          Clicking the logo always takes you back to the dashboard (home).
      ---------------------------------------------------------------- */}
      <div className="px-5 py-5 border-b border-zinc-800">
        <Link
          href="/dashboard"
          className="flex items-center gap-2 group"
          aria-label="Dartly — go to dashboard"
        >
          {/* Simple geometric mark — two overlapping squares */}
          <div className="relative w-7 h-7 shrink-0">
            <div className="absolute inset-0 bg-indigo-500 rounded-sm" />
            <div className="absolute top-1 left-1 right-0 bottom-0 border-2 border-indigo-300 rounded-sm" />
          </div>
          <span className="text-base font-semibold tracking-tight text-zinc-50 group-hover:text-indigo-400 transition-colors">
            dartly
          </span>
        </Link>
      </div>

      {/* ----------------------------------------------------------------
          Navigation links
      ---------------------------------------------------------------- */}
      <nav className="flex-1 px-3 py-4 space-y-0.5" aria-label="Site sections">
        {NAV_ITEMS.map((item) => {
          // A link is "active" if the current URL starts with its href.
          // e.g. /dashboard/some-job-id still counts as Dashboard being active.
          const isActive = pathname === item.href || pathname.startsWith(`${item.href}/`);

          return (
            <Link
              key={item.href}
              href={item.href}
              aria-current={isActive ? "page" : undefined}
              className={cn(
                // Base styles shared by all nav links
                "flex items-center gap-3 px-3 py-2 rounded-md text-sm transition-colors",
                // Active state (from ui-ux-standards.md Section 5)
                isActive
                  ? "bg-indigo-500/10 text-indigo-400 font-medium border-l-2 border-indigo-500 pl-[10px]"
                  : // Inactive state
                    "text-zinc-400 hover:bg-zinc-800/60 hover:text-zinc-100 border-l-2 border-transparent pl-[10px]"
              )}
            >
              {/* Icon */}
              <span className="shrink-0">{item.icon}</span>
              {/* Label */}
              <span>{item.label}</span>
            </Link>
          );
        })}
      </nav>

      {/* ----------------------------------------------------------------
          Bottom of sidebar — placeholder for user info / logout
          (Auth stories S1-010 through S1-015 will fill this in)
      ---------------------------------------------------------------- */}
      <div className="px-3 py-4 border-t border-zinc-800">
        <Link
          href="/profile"
          className="flex items-center gap-3 px-3 py-2 rounded-md text-sm text-zinc-400 hover:text-zinc-200 hover:bg-zinc-800/60 transition-colors"
        >
          <div
            aria-hidden="true"
            className="w-7 h-7 rounded-full bg-indigo-500/20 border border-indigo-500/30 flex items-center justify-center text-xs font-medium text-indigo-400 shrink-0"
          >
            {initials}
          </div>
          <span className="truncate">{fullName}</span>
        </Link>
      </div>
    </aside>
  );
}

