"use client";

import { useState } from "react";
import { Input } from "@/components/ui/input";
import { Modal } from "@/components/ui/modal";
import type { ProfileData } from "@/types/profile";

type IdentitySectionProps = {
  profile: ProfileData;
  onUpdate: (fields: Partial<ProfileData>) => void;
};

export function IdentitySection({ profile, onUpdate }: IdentitySectionProps) {
  const [modalOpen, setModalOpen] = useState(false);
  const [firstName, setFirstName] = useState(profile.firstName ?? "");
  const [lastName, setLastName] = useState(profile.lastName ?? "");
  const [email, setEmail] = useState(profile.email ?? "");
  const [phone, setPhone] = useState(profile.phone ?? "");
  const [location, setLocation] = useState(profile.location ?? "");

  function openModal() {
    setFirstName(profile.firstName ?? "");
    setLastName(profile.lastName ?? "");
    setEmail(profile.email ?? "");
    setPhone(profile.phone ?? "");
    setLocation(profile.location ?? "");
    setModalOpen(true);
  }

  function handleSave() {
    onUpdate({
      firstName: firstName.trim() || undefined,
      lastName: lastName.trim() || undefined,
      email: email.trim() || undefined,
      phone: phone.trim() || undefined,
      location: location.trim() || undefined,
    });
    setModalOpen(false);
  }

  const fields = [
    {
      label: "Name",
      value: [profile.firstName, profile.lastName].filter(Boolean).join(" ") || null,
    },
    { label: "Email", value: profile.email || null },
    { label: "Phone", value: profile.phone || null },
    { label: "Location", value: profile.location || null },
  ];

  return (
    <div className="bg-zinc-900 border border-zinc-700 rounded-lg shadow-sm p-6">
      <div className="flex items-center justify-between mb-4">
        <h2 className="text-lg font-semibold text-zinc-50">Identity & Contact</h2>
        <button
          type="button"
          onClick={openModal}
          className="bg-zinc-800 border border-zinc-700 hover:bg-zinc-700 text-zinc-50 px-4 py-2 rounded-md text-sm font-medium"
        >
          Edit
        </button>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 text-sm">
        {fields.map((field) => (
          <div key={field.label}>
            <p className="text-xs text-zinc-500">{field.label}</p>
            <p className="text-zinc-50">
              {field.value || <span className="text-zinc-600">Not set</span>}
            </p>
          </div>
        ))}
      </div>

      <Modal open={modalOpen} onClose={() => setModalOpen(false)} title="Edit Identity & Contact">
        <div className="space-y-4">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <Input
              id="identity-firstName"
              label="First Name"
              placeholder="Jane"
              value={firstName}
              onChange={(e) => setFirstName(e.target.value)}
            />
            <Input
              id="identity-lastName"
              label="Last Name"
              placeholder="Doe"
              value={lastName}
              onChange={(e) => setLastName(e.target.value)}
            />
          </div>
          <Input
            id="identity-email"
            label="Email"
            type="email"
            placeholder="jane@example.com"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
          />
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <Input
              id="identity-phone"
              label="Phone"
              type="tel"
              placeholder="(555) 123-4567"
              value={phone}
              onChange={(e) => setPhone(e.target.value)}
            />
            <Input
              id="identity-location"
              label="Location"
              placeholder="New York, NY"
              value={location}
              onChange={(e) => setLocation(e.target.value)}
            />
          </div>
          <div className="flex justify-end gap-3 pt-2">
            <button
              type="button"
              onClick={() => setModalOpen(false)}
              className="bg-zinc-800 border border-zinc-700 hover:bg-zinc-700 text-zinc-50 px-4 py-2 rounded-md text-sm font-medium"
            >
              Cancel
            </button>
            <button
              type="button"
              onClick={handleSave}
              className="bg-indigo-500 hover:bg-indigo-600 text-zinc-50 px-4 py-2 rounded-md text-sm font-medium"
            >
              Save
            </button>
          </div>
        </div>
      </Modal>
    </div>
  );
}

import type { Job, JobStage } from "@/types/job";

type JobCardProps = {
  job: Job;
  onEdit?: (job: Job) => void;
  onDelete?: (id: string) => void;
};

const STAGE_STYLES: Record<JobStage, string> = {
  Interested: "bg-zinc-900 text-zinc-400",
  Applied: "bg-blue-950 text-blue-400",
  Interview: "bg-yellow-950 text-yellow-400",
  Offer: "bg-green-950 text-green-400",
  Rejected: "bg-red-950 text-red-400",
  Archived: "bg-zinc-900 text-zinc-500",
};

export default function JobCard({ job, onEdit, onDelete }: JobCardProps) {
  return (
    <div className="bg-zinc-900 border border-zinc-700 rounded-lg shadow-sm p-6">
      {/* Top: Title + Stage */}
      <div className="flex items-start justify-between gap-3">
        <div className="min-w-0">
          <h2 className="text-base font-medium text-zinc-50 truncate">
            {job.title}
          </h2>
          <p className="text-sm text-zinc-400">{job.company}</p>
        </div>
        <span
          className={`shrink-0 rounded-md px-2.5 py-1 text-xs font-medium ${STAGE_STYLES[job.stage]}`}
        >
          {job.stage}
        </span>
      </div>

      {/* Details */}
      <div className="mt-4 space-y-1 text-sm text-zinc-500">
        {job.location && <p>{job.location}</p>}
        <p>Last activity: {job.lastActivityDate}</p>
      </div>

      {/* Bottom: Priority + Actions */}
      <div className="mt-4 flex items-center justify-between">
        {job.priority ? (
          <span className="bg-yellow-950 text-yellow-400 rounded-md px-2 py-1 text-xs font-medium">
            Priority
          </span>
        ) : (
          <div />
        )}

        <div className="flex gap-2">
          {onEdit && (
            <button
              type="button"
              onClick={() => onEdit(job)}
              className="bg-zinc-800 border border-zinc-700 hover:bg-zinc-700 text-zinc-50 rounded-md px-3 py-1 text-xs font-medium"
              aria-label={`Edit ${job.title}`}
            >
              <svg
                width="14"
                height="14"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2"
                strokeLinecap="round"
                strokeLinejoin="round"
                aria-hidden="true"
              >
                <path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7" />
                <path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z" />
              </svg>
            </button>
          )}

          {onDelete && (
            <button
              type="button"
              onClick={() => onDelete(job.id)}
              className="bg-red-600 hover:bg-red-700 text-zinc-50 rounded-md px-3 py-1 text-xs font-medium"
              aria-label={`Delete ${job.title}`}
            >
              <svg
                width="14"
                height="14"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2"
                strokeLinecap="round"
                strokeLinejoin="round"
                aria-hidden="true"
              >
                <polyline points="3 6 5 6 21 6" />
                <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2" />
              </svg>
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

