3	import { useCallback, useEffect, useState } from "react";
4	
5	type ToastType = "success" | "error" | "info";
6	
7	type Toast = {
8	  id: number;
9	  message: string;
10	  type: ToastType;
11	  exiting: boolean;
12	};
13	
14	type AddToast = (message: string, type?: ToastType) => void;
15	
16	let nextId = 0;
17	const listeners = new Set<AddToast>();
18	
19	export function showToast(message: string, type: ToastType = "success") {
20	  for (const listener of listeners) {
21	    listener(message, type);
22	  }
23	}
24	
25	const ACCENT: Record<ToastType, string> = {
26	  success: "border-l-emerald-400",
27	  error: "border-l-red-400",
28	  info: "border-l-indigo-400",
29	};
30	
31	const ICON_BG: Record<ToastType, string> = {
32	  success: "bg-emerald-400/10 text-emerald-400",
33	  error: "bg-red-400/10 text-red-400",
34	  info: "bg-indigo-400/10 text-indigo-400",
35	};
36	
37	const PROGRESS: Record<ToastType, string> = {
38	  success: "bg-emerald-400",
39	  error: "bg-red-400",
40	  info: "bg-indigo-400",
41	};
42	
43	function ToastIcon({ type }: { type: ToastType }) {
44	  if (type === "success") {
45	    return (
46	      <svg
47	        width="16"
48	        height="16"
49	        viewBox="0 0 24 24"
50	        fill="none"
51	        stroke="currentColor"
52	        strokeWidth="2.5"
53	        strokeLinecap="round"
54	        strokeLinejoin="round"
55	        aria-hidden="true"
56	      >
57	        <polyline points="20 6 9 17 4 12" />
58	      </svg>
59	    );
60	  }
61	  if (type === "error") {
62	    return (
63	      <svg
64	        width="16"
65	        height="16"
66	        viewBox="0 0 24 24"
67	        fill="none"
68	        stroke="currentColor"
69	        strokeWidth="2.5"
70	        strokeLinecap="round"
71	        strokeLinejoin="round"
72	        aria-hidden="true"
73	      >
74	        <line x1="18" y1="6" x2="6" y2="18" />
75	        <line x1="6" y1="6" x2="18" y2="18" />
76	      </svg>
77	    );
78	  }
79	  return (
80	    <svg
81	      width="16"
82	      height="16"
83	      viewBox="0 0 24 24"
84	      fill="none"
85	      stroke="currentColor"
86	      strokeWidth="2.5"
87	      strokeLinecap="round"
88	      strokeLinejoin="round"
89	      aria-hidden="true"
90	    >
91	      <circle cx="12" cy="12" r="10" />
92	      <line x1="12" y1="16" x2="12" y2="12" />
93	      <line x1="12" y1="8" x2="12.01" y2="8" />
94	    </svg>
95	  );
96	}
97	
98	const DURATION = 3500;
99	
100	export function ToastContainer() {
101	  const [toasts, setToasts] = useState<Toast[]>([]);
102	
103	  const addToast = useCallback((message: string, type: ToastType = "success") => {
104	    const id = nextId++;
105	    setToasts((prev) => [...prev, { id, message, type, exiting: false }]);
106	
107	    setTimeout(() => {
108	      setToasts((prev) => prev.map((t) => (t.id === id ? { ...t, exiting: true } : t)));
109	    }, DURATION);
110	
111	    setTimeout(() => {
112	      setToasts((prev) => prev.filter((t) => t.id !== id));
113	    }, DURATION + 300);
114	  }, []);
115	
116	  useEffect(() => {
117	    listeners.add(addToast);
118	    return () => {
119	      listeners.delete(addToast);
120	    };
121	  }, [addToast]);
122	
123	  function dismiss(id: number) {
124	    setToasts((prev) => prev.map((t) => (t.id === id ? { ...t, exiting: true } : t)));
125	    setTimeout(() => {
126	      setToasts((prev) => prev.filter((t) => t.id !== id));
127	    }, 300);
128	  }
129	
130	  if (toasts.length === 0) return null;
131	
132	  return (
133	    <div
134	      className="fixed bottom-6 right-6 z-[60] flex flex-col gap-3 pointer-events-none"
135	      aria-live="polite"
136	    >
137	      {toasts.map((toast) => (
138	        <div
139	          key={toast.id}
140	          role="alert"
141	          className={[
142	            "pointer-events-auto relative flex items-center gap-3 min-w-[320px] max-w-[420px]",
143	            "bg-zinc-900/95 backdrop-blur-sm border border-zinc-700/60 border-l-[3px] rounded-lg shadow-2xl overflow-hidden",
144	            ACCENT[toast.type],
145	            toast.exiting
146	              ? "animate-[toastOut_300ms_ease-in_forwards]"
147	              : "animate-[toastIn_300ms_ease-out]",
148	          ].join(" ")}
149	        >
150	          <div className={`ml-3 shrink-0 rounded-md p-1.5 ${ICON_BG[toast.type]}`}>
151	            <ToastIcon type={toast.type} />
152	          </div>
153	
154	          <p className="flex-1 py-3 pr-2 text-sm text-zinc-200 leading-snug">{toast.message}</p>
155	
156	          <button
157	            type="button"
