7	import "react-day-picker/style.css";
8	import { Label } from "@/components/ui/label";
9	
10	type DatePickerProps = {
11	  id: string;
12	  label?: string;
13	  value: string;
14	  onChange: (value: string) => void;
15	  placeholder?: string;
16	  error?: string;
17	  required?: boolean;
18	  disabled?: boolean;
19	};
20	
21	export function DatePicker({
22	  id,
23	  label,
24	  value,
25	  onChange,
26	  placeholder = "Select date",
27	  error,
28	  required,
29	  disabled,
30	}: DatePickerProps) {
31	  const [open, setOpen] = useState(false);
32	  const [mounted, setMounted] = useState(false);
33	  const triggerRef = useRef<HTMLButtonElement>(null);
34	
35	  useEffect(() => {
36	    setMounted(true);
37	  }, []);
38	
39	  useEffect(() => {
40	    if (!open) return;
41	    function onKey(e: KeyboardEvent) {
42	      if (e.key === "Escape") setOpen(false);
43	    }
44	    document.addEventListener("keydown", onKey);
45	    return () => document.removeEventListener("keydown", onKey);
46	  }, [open]);
47	
48	  useEffect(() => {
49	    if (!open) return;
50	    function onClick(e: MouseEvent) {
51	      const t = e.target as Node;
52	      if (triggerRef.current?.contains(t)) return;
53	      const popover = document.getElementById(`${id}-popover`);
54	      if (popover?.contains(t)) return;
55	      setOpen(false);
56	    }
57	    document.addEventListener("mousedown", onClick);
58	    return () => document.removeEventListener("mousedown", onClick);
59	  }, [id, open]);
60	
61	  const selected = value ? parse(value, "yyyy-MM-dd", new Date()) : undefined;
62	  const displayValue = selected ? format(selected, "MMM yyyy") : "";
63	
64	  function handleSelect(date: Date | undefined) {
65	    if (date) {
66	      onChange(format(date, "yyyy-MM-dd"));
67	      setOpen(false);
68	    }
69	  }
70	
71	  function getPopoverStyle(): React.CSSProperties {
72	    if (!triggerRef.current) return { display: "none" };
73	    const rect = triggerRef.current.getBoundingClientRect();
74	    const spaceBelow = window.innerHeight - rect.bottom;
75	    const approxHeight = 340;
76	    const openAbove = spaceBelow < approxHeight;
77	    return {
78	      position: "fixed",
79	      top: openAbove ? undefined : rect.bottom + 4,
80	      bottom: openAbove ? window.innerHeight - rect.top + 4 : undefined,
81	      left: rect.left,
82	    };
83	  }
84	
85	  return (
86	    <div>
87	      {label && (
88	        <Label htmlFor={id} required={required}>
89	          {label}
90	        </Label>
91	      )}
92	      <button
93	        id={id}
94	        ref={triggerRef}
95	        type="button"
96	        disabled={disabled}
97	        onClick={() => setOpen((v) => !v)}
98	        className={[
99	          "w-full bg-zinc-800 border rounded-md px-3 py-2 text-sm text-left flex items-center justify-between gap-2",
100	          "focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent",
101	          "disabled:opacity-50 disabled:cursor-not-allowed",
102	          error ? "border-red-500" : "border-zinc-700",
103	        ].join(" ")}
104	        aria-label={value ? `Selected: ${displayValue}` : placeholder}
105	        aria-haspopup="dialog"
106	        aria-expanded={open}
107	      >
108	        <span className={value ? "text-zinc-50" : "text-zinc-500"}>
109	          {value ? displayValue : placeholder}
110	        </span>
111	        <svg
112	          className="shrink-0 text-zinc-500"
113	          width="16"
114	          height="16"
115	          viewBox="0 0 24 24"
116	          fill="none"
117	          stroke="currentColor"
118	          strokeWidth="2"
119	          strokeLinecap="round"
120	          strokeLinejoin="round"
121	          aria-hidden="true"
122	        >
123	          <rect x="3" y="4" width="18" height="18" rx="2" ry="2" />
124	          <line x1="16" y1="2" x2="16" y2="6" />
125	          <line x1="8" y1="2" x2="8" y2="6" />
126	          <line x1="3" y1="10" x2="21" y2="10" />
127	        </svg>
128	      </button>
129	
130	      {mounted &&
131	        open &&
132	        createPortal(
133	          <div
134	            id={`${id}-popover`}
135	            className="rdp-dartly z-[60] bg-zinc-900 border border-zinc-700 rounded-lg shadow-2xl p-3 animate-[scaleIn_150ms_ease-out]"
136	            style={getPopoverStyle()}
137	            role="dialog"
138	            aria-label="Choose date"
139	          >
140	            <DayPicker
141	              mode="single"
142	              captionLayout="dropdown"
143	              selected={selected}
144	              onSelect={handleSelect}
145	              startMonth={new Date(1970, 0)}
146	              endMonth={new Date(2035, 11)}
147	              defaultMonth={selected ?? new Date()}
148	            />
149	          </div>,
150	          document.body
151	        )}
152	
153	      {error && (
154	        <p id={`${id}-error`} className="mt-1 text-xs text-red-400">
155	          {error}
156	        </p>
157	      )}
158	    </div>
159	  );
160	}
