9	type EducationSectionProps = {
10	  educations: Education[];
11	  onUpdate: (educations: Education[], message?: string) => void;
12	};
13	
14	function formatDate(date: string | undefined): string {
15	  if (!date) return "";
16	  const d = new Date(date);
17	  return d.toLocaleDateString("en-US", { month: "short", year: "numeric" });
18	}
19	
20	export function EducationSection({ educations, onUpdate }: EducationSectionProps) {
21	  const [modalOpen, setModalOpen] = useState(false);
22	  const [editingIndex, setEditingIndex] = useState<number | null>(null);
23	  const [deleteIndex, setDeleteIndex] = useState<number | null>(null);
24	
25	  function handleAdd() {
26	    setEditingIndex(null);
27	    setModalOpen(true);
28	  }
29	
30	  function handleEdit(index: number) {
31	    setEditingIndex(index);
32	    setModalOpen(true);
33	  }
34	
35	  function handleDelete(index: number) {
36	    setDeleteIndex(index);
37	  }
38	
39	  function confirmDelete() {
40	    if (deleteIndex === null) return;
41	    onUpdate(
42	      educations.filter((_, i) => i !== deleteIndex),
43	      "Education removed"
44	    );
45	    setDeleteIndex(null);
46	  }
47	
48	  const deleteItem = deleteIndex !== null ? educations[deleteIndex] : null;
49	
50	  function handleSave(education: Education) {
51	    if (editingIndex !== null) {
52	      const updated = educations.map((edu, i) => (i === editingIndex ? education : edu));
53	      onUpdate(updated, "Education updated");
54	    } else {
55	      onUpdate([...educations, { ...education, id: crypto.randomUUID() }], "Education added");
56	    }
57	    setModalOpen(false);
58	    setEditingIndex(null);
59	  }
60	
61	  return (
62	    <div className="bg-zinc-900 border border-zinc-700 rounded-lg shadow-sm p-6">
63	      <h2 className="text-lg font-semibold text-zinc-50 mb-4">Education</h2>
64	      {educations.length === 0 ? (
65	        <div className="border border-dashed border-zinc-700 rounded-lg py-8 flex flex-col items-center gap-2">
66	          <p className="text-sm text-zinc-500">No education added yet</p>
67	          <button
68	            type="button"
69	            onClick={handleAdd}
70	            className="text-sm text-indigo-400 hover:text-indigo-300"
71	          >
72	            + Add your first education
73	          </button>
74	        </div>
75	      ) : (
76	        <div className="space-y-3">
77	          {educations.map((edu, index) => (
78	            // biome-ignore lint/a11y/useSemanticElements: div needed to nest child buttons
79	            <div
80	              key={edu.id || index}
81	              role="button"
82	              tabIndex={0}
83	              className="group rounded-lg border border-zinc-700 bg-zinc-950/40 p-4 hover:border-zinc-600 transition-colors cursor-pointer"
84	              onClick={() => handleEdit(index)}
85	              onKeyDown={(e) => {
86	                if (e.key === "Enter" || e.key === " ") handleEdit(index);
87	              }}
88	            >
89	              <div className="flex items-start justify-between">
90	                <div className="flex-1 min-w-0">
91	                  <p className="text-sm font-medium text-zinc-50">
92	                    {edu.degree || <span className="text-zinc-600">No degree</span>}
93	                    {edu.fieldOfStudy && (
94	                      <span className="text-zinc-400 font-normal"> in {edu.fieldOfStudy}</span>
95	                    )}
96	                  </p>
97	                  <p className="text-sm text-zinc-400">
98	                    {edu.institution || <span className="text-zinc-600">No institution</span>}
99	                  </p>
100	                  <p className="text-xs text-zinc-500 mt-0.5">
101	                    {[formatDate(edu.startDate), formatDate(edu.endDate)]
102	                      .filter(Boolean)
103	                      .join(" - ")}
104	                  </p>
105	                  {edu.gpa && (
106	                    <span className="text-xs bg-zinc-800 text-zinc-300 px-2 py-0.5 rounded mt-1.5 inline-block">
107	                      GPA: {edu.gpa}
108	                    </span>
109	                  )}
110	                </div>
111	                <div className="flex items-center gap-1 ml-2">
112	                  <button
