  .string()
  .regex(/^\d{4}-\d{2}-\d{2}$/, "Expected YYYY-MM-DD")
  .or(z.literal(""));

export const ExperienceSchema = z.object({
  id: z.string(),
  type: z.enum(["EMPLOYMENT", "PROJECT"]),
  title: z.string().trim().min(1).max(200),
  organization: z.string().trim().max(200),
  startDate: IsoDateString,
  endDate: IsoDateString.optional(),
  isCurrent: z.boolean(),
  description: z.string().max(5000),
});

export const EducationSchema = z.object({
  id: z.string(),
  institution: z.string().trim().min(1).max(200),
  degree: z.string().trim().max(200),
  fieldOfStudy: z.string().trim().max(200),
  startDate: IsoDateString,
  endDate: IsoDateString,
  gpa: z.string().trim().max(10),
});

export const SkillSchema = z.object({
  id: z.string(),
  name: z.string().trim().min(1).max(100),
});

export const ProfilePatchSchema = z
  .object({
    firstName: z.string().trim().max(100).nullable(),
    lastName: z.string().trim().max(100).nullable(),
    email: z.email().nullable(),
    phone: z.string().trim().max(50).nullable(),
    location: z.string().trim().max(200).nullable(),
    headline: z.string().trim().max(200).nullable(),
    summary: z.string().trim().max(5000).nullable(),
    targetRoles: z.array(z.string().trim().max(100)).max(50),
    targetLocations: z.array(z.string().trim().max(100)).max(50),
    workModePreference: z.enum(["Remote", "Hybrid", "On-site", "Flexible"]).nullable(),
    salaryPreference: z.number().int().min(0).max(10_000_000).nullable(),
    professionalLinks: z.record(z.string(), z.url()).nullable(),
    experiences: z.array(ExperienceSchema).max(50),
    educations: z.array(EducationSchema).max(50),
    skills: z.array(SkillSchema).max(200),
  })
  .partial();
```

