import JobForm from "@/components/dashboard/job_form";
import type { Job } from "@/types/job";

type AddJobModalProps = {
  isOpen: boolean;
  initialValues?: Job | null;
  onSubmit: (job: Job) => void;
  onClose: () => void;
};

export default function AddJobModal({ isOpen, initialValues = null, onSubmit, onClose }: AddJobModalProps) {
  return (
    <Modal open={isOpen} onClose={onClose} title={initialValues ? "Edit Job" : "Add Job"}>
      <JobForm initialValues={initialValues} onSubmit={onSubmit} onCancel={onClose} />
    </Modal>
  );
}
```

`Modal` is hardcoded to `max-w-lg`, but `AddJobModal` was `max-w-2xl`. The job form has many fields and needs the wider layout. Add a `maxWidth` prop to `Modal`:

```tsx
type ModalProps = {
  open: boolean;
  onClose: () => void;
  title?: string;
  children: React.ReactNode;
  maxWidth?: "sm" | "md" | "lg" | "xl" | "2xl";
};

const MAX_WIDTH_CLASS = {
  sm: "max-w-sm",
  md: "max-w-md",
  lg: "max-w-lg",
  xl: "max-w-xl",
  "2xl": "max-w-2xl",
};

export function Modal({ open, onClose, title, children, maxWidth = "lg" }: ModalProps) {
  // ...
  // change `max-w-lg` in the inner div's className to:
  // `${MAX_WIDTH_CLASS[maxWidth]}`
}
```

Then in `AddJobModal`, pass `maxWidth="2xl"`. Tailwind needs the literal class strings to appear somewhere statically — using a const map like `MAX_WIDTH_CLASS` works because Tailwind's JIT scans the source files and sees each `max-w-*` literal.

